+import fs from 'fs';
+import path from 'path';
+
+describe('spotlight architecture', () => {
+    it('should keep spotlight feature hooks centralized in useSpotlight provider only', () => {
+        const appRoot = path.resolve(__dirname, '..');
+        const searchFieldSource = fs.readFileSync(
+            path.join(appRoot, 'components/layout/search/SearchField.tsx'),
+            'utf8'
+        );
+        const spotlightSource = fs.readFileSync(path.join(appRoot, 'components/useSpotlight.tsx'), 'utf8');
+
+        expect(spotlightSource).toContain('SEARCH_DISCOVERY_MIN_ELIGIBLE_ITEMS');
+        expect(searchFieldSource).not.toContain('useSpotlightOnFeature(');
+        expect(searchFieldSource).not.toContain('useSpotlightShow(');
+        expect(spotlightSource).toContain('useSpotlightOnFeature(');
+        expect(spotlightSource).toContain('useSpotlightShow(');
+    });
+});
